SELECT * FROM book_pages
WHERE book_id = #{bookId,javaType=java.util.UUID,jdbcType=OTHER}
ORDER BY page_order ASC

mapper.update:
UPDATE book_pages
SET slots = #{slots}::jsonb, layout_edited_at = NOW(), updated_at = NOW()
WHERE id = #{id,javaType=java.util.UUID,jdbcType=OTHER}

UPDATE book_pages
SET layout_mode = 'customized', layout_edited_at = NOW(), updated_at = NOW()
WHERE id = #{id,javaType=java.util.UUID,jdbcType=OTHER}

UPDATE book_pages
SET layout_mode = 'skeleton', layout_edited_at = NULL, updated_at = NOW()
WHERE id = #{id,javaType=java.util.UUID,jdbcType=OTHER}
